mapper.select:
SELECT COUNT(*)
FROM course c
WHERE 1=1

    AND c.course_no LIKE CONCAT('%', #{course_no}, '%')


    AND c.course_name LIKE CONCAT('%', #{course_name}, '%')


    AND c.Credits = #{credit}


    AND c.DayOfWeek = #{day_of_week}


    AND c.TimePeriod = #{time_slot}

SELECT c.courseID, c.course_no, c.courseName, c.Credits, c.DayOfWeek, c.TimePeriod
FROM course c
WHERE 1=1

    AND c.course_no LIKE CONCAT('%', #{course_no}, '%')


    AND c.courseName LIKE CONCAT('%', #{course_name}, '%')


    AND c.Credits = #{credit}


    AND c.DayOfWeek = #{day_of_week}


    AND c.TimePeriod = #{time_slot}

LIMIT #{page}, #{pageSize}
